package main

import (
	"sort"
)

type Element struct {
	limit int64
	value int64
}

func solve(value []int64, limit []int64) int64 {
	n := len(value)
	elements := make([]Element, n)
	for i := 0; i < n; i++ {
		elements[i] = Element{limit[i], value[i]}
	}

	sort.Slice(elements, func(i, j int) bool {
		if elements[i].limit != elements[j].limit {
			return elements[i].limit < elements[j].limit
		}
		return elements[i].value > elements[j].value
	})

	var res, active int64
	for _, elem := range elements {
		if active < elem.limit {
			res += elem.value
			active++
		}
	}
	return res
}
